"""Migrations for 3.3.3 release."""

import re
from netskope.common.utils import DBConnector, Collections


def replace_name(name):
    """Replace plugin name function."""
    return re.sub(r"[^a-zA-Z0-9 ]+", " ", name).strip()


if __name__ == "__main__":
    connector = DBConnector()
    # for tenant
    for tenant in connector.collection(Collections.NETSKOPE_TENANTS).find({}):
        if not re.match(r"^[a-zA-Z0-9 ]+$", tenant["name"]):
            connector.collection(Collections.NETSKOPE_TENANTS).update_one(
                {"_id": tenant["_id"]},
                {"$set": {"name": replace_name(tenant["name"])}},
            )
            connector.collection(Collections.SCHEDULES).update_one(
                {"name": f"tenant.{tenant['name']}"},
                {
                    "$set": {
                        "name": f"tenant.{replace_name(tenant['name'])}",
                        "args.0": replace_name(tenant["name"]),
                    }
                },
            )
            connector.collection(Collections.SCHEDULES).update_one(
                {"name": f"tenant.{tenant['name']}.events"},
                {
                    "$set": {
                        "name": f"tenant.{replace_name(tenant['name'])}.events",
                        "args.0": replace_name(tenant["name"]),
                    }
                },
            )
            for cte_conf in connector.collection(
                Collections.CONFIGURATIONS
            ).find({"tenant": tenant["name"]}):
                connector.collection(Collections.CONFIGURATIONS).update_one(
                    {"_id": cte_conf["_id"]},
                    {"$set": {"tenant": replace_name(tenant["name"])}},
                )
            for cto_conf in connector.collection(
                Collections.ITSM_CONFIGURATIONS
            ).find({"tenant": tenant["name"]}):
                connector.collection(
                    Collections.ITSM_CONFIGURATIONS
                ).update_one(
                    {"_id": cto_conf["_id"]},
                    {"$set": {"tenant": replace_name(tenant["name"])}},
                )
            for cre_conf in connector.collection(
                Collections.CRE_CONFIGURATIONS
            ).find({"tenant": tenant["name"]}):
                connector.collection(
                    Collections.CRE_CONFIGURATIONS
                ).update_one(
                    {"_id": cre_conf["_id"]},
                    {"$set": {"tenant": replace_name(tenant["name"])}},
                )
            for cls_conf in connector.collection(
                Collections.CLS_CONFIGURATIONS
            ).find({"tenant": tenant["name"]}):
                connector.collection(
                    Collections.CLS_CONFIGURATIONS
                ).update_one(
                    {"_id": cls_conf["_id"]},
                    {"$set": {"tenant": replace_name(tenant["name"])}},
                )
    # For CTE
    for plugin in connector.collection(Collections.CONFIGURATIONS).find({}):
        if not re.match(r"^[a-zA-Z0-9 ]+$", plugin["name"]):
            connector.collection(Collections.CONFIGURATIONS).update_one(
                {"_id": plugin["_id"]},
                {"$set": {"name": replace_name(plugin["name"])}},
            )
            connector.collection(Collections.SCHEDULES).update_one(
                {"name": plugin["name"]},
                {
                    "$set": {
                        "name": replace_name(plugin["name"]),
                        "args.0": replace_name(plugin["name"]),
                    }
                },
            )
            connector.collection(Collections.INDICATORS).update_many(
                {"source": plugin["name"]},
                {"$set": {"source": replace_name(plugin["name"])}},
            )
            for brule in connector.collection(
                Collections.CTE_BUSINESS_RULES
            ).find({}):
                if brule["sharedWith"].get(plugin["name"], None):
                    brule["sharedWith"][replace_name(plugin["name"])] = brule[
                        "sharedWith"
                    ].pop(plugin["name"])
                sharedWith = brule.get("sharedWith", {})
                for destination in brule["sharedWith"].values():
                    if plugin["name"] in destination.keys():
                        destination[
                            replace_name(plugin["name"])
                        ] = destination.pop(plugin["name"])

                connector.collection(
                    Collections.CTE_BUSINESS_RULES
                ).replace_one({"name": brule["name"]}, brule)
    # For CLS
    for plugin in connector.collection(Collections.CLS_CONFIGURATIONS).find(
        {}
    ):
        if not re.match(r"^[a-zA-Z0-9 ]+$", plugin["name"]):
            connector.collection(Collections.CLS_CONFIGURATIONS).update_one(
                {"_id": plugin["_id"]},
                {"$set": {"name": replace_name(plugin["name"])}},
            )
            for brule in connector.collection(
                Collections.CLS_BUSINESS_RULES
            ).find({}):
                if brule["siemMappings"].get(plugin["name"], None):
                    brule["siemMappings"][
                        replace_name(plugin["name"])
                    ] = brule["siemMappings"].pop(plugin["name"])
                for destination in brule["siemMappings"].values():
                    if plugin["name"] in destination:
                        destination.remove(plugin["name"])
                        destination.append(replace_name(plugin["name"]))

                connector.collection(
                    Collections.CLS_BUSINESS_RULES
                ).replace_one({"name": brule["name"]}, brule)

    # For ITSM
    for plugin in connector.collection(Collections.ITSM_CONFIGURATIONS).find(
        {}
    ):
        if not re.match(r"^[a-zA-Z0-9 ]+$", plugin["name"]):
            connector.collection(Collections.ITSM_CONFIGURATIONS).update_one(
                {"_id": plugin["_id"]},
                {"$set": {"name": replace_name(plugin["name"])}},
            )
            connector.collection(Collections.SCHEDULES).update_one(
                {"name": f'itsm.{plugin["name"]}'},
                {
                    "$set": {
                        "name": f'itsm.{replace_name(plugin["name"])}',
                        "args.0": replace_name(plugin["name"]),
                    }
                },
            )
            for brule in connector.collection(
                Collections.ITSM_BUSINESS_RULES
            ).find({}):
                if brule["queues"].get(plugin["name"], None):
                    brule["queues"][replace_name(plugin["name"])] = brule[
                        "queues"
                    ].pop(plugin["name"])
                connector.collection(
                    Collections.ITSM_BUSINESS_RULES
                ).replace_one({"name": brule["name"]}, brule)

    connector.collection(Collections.CLS_CONFIGURATIONS).update_many(
        {"attributeMapping": "Microsoft Cloud App Security Default Mappings"},
        {"$set": {
            "attributeMapping": "Microsoft Defender for Cloud Apps Default Mappings"
        }}
    )

    for stix_taxi in connector.collection(Collections.CONFIGURATIONS).find(
        {"plugin": "netskope.plugins.Default.stix_taxii.main"}
    ):
        if stix_taxi["parameters"].get("version", "0") == "2":
            connector.collection(Collections.CONFIGURATIONS).update_one(
                {"name": stix_taxi["name"]},
                {"$set":
                    {
                        "parameters.version": "2.0"
                    }}
            )

    # for 2.x to 3.x
    for plugin in connector.collection(Collections.ITSM_CONFIGURATIONS).find(
        {}
    ):
        for rule in connector.collection(Collections.ITSM_BUSINESS_RULES).find(
            {}
        ):
            if rule.get("queues", {}).get(plugin["name"], []):
                for field_mappings in rule["queues"][plugin["name"]]:
                    if field_mappings.get("defaultMappings", None) is None:
                        field_mappings["defaultMappings"] = {
                            "mappings": plugin.get("mappings", []),
                            "dedup": []
                        }
            connector.collection(Collections.ITSM_BUSINESS_RULES).replace_one(
                {"name": rule["name"]}, rule
            )

